import os
import shutil
import gzip
import bz2
import zipfile
import winrar

def quick_backup(directory_path, format):
    if format == 'tar.gz':
        shutil.make_archive(directory_path, 'gztar', directory_path)
    elif format == 'tar.bz2':
        shutil.make_archive(directory_path, 'bztar', directory_path)
